parameters.responseBody:
={{ JSON.stringify({
  "status": "success",
  "message": "Job search completed successfully",
  "data": {
    "total_jobs": $json.total_jobs,
    "jobs_found": $json.jobs,
    "application_messages": $json.messages,
    "searched_at": new Date().toISOString()
  }
}) }}

={{ JSON.stringify({
  "status": "no_results",
  "message": "No jobs found matching the criteria",
  "data": {
    "search_criteria": $json.search_criteria,
    "searched_at": new Date().toISOString()
  }
}) }}
